#include <math.h>

const int LED_PIN = 9;
const float STEP = 0.05f;

void setup() {
  pinMode(LED_PIN, OUTPUT);
}

void loop() {
  static float phase = 0.0f;
  float v = (sinf(phase) + 1.0f) * 0.5f;
  analogWrite(LED_PIN, (int)(v * 255.0f));
  phase += STEP;
  if (phase > TWO_PI) phase -= TWO_PI;
  delay(15);
}
