#include <Arduino.h>

const int PULSE_PIN = 2;
volatile unsigned long edgeCount = 0;
unsigned long lastReport = 0;

void onRise() {
  edgeCount++;
}

void setup() {
  Serial.begin(115200);
  pinMode(PULSE_PIN, INPUT);
  attachInterrupt(digitalPinToInterrupt(PULSE_PIN), onRise, RISING);
}

void loop() {
  unsigned long now = millis();
  if (now - lastReport >= 1000) {
    noInterrupts();
    unsigned long c = edgeCount;
    edgeCount = 0;
    interrupts();
    Serial.print("Hz: ");
    Serial.println(c);
    lastReport = now;
  }
}
