#include <Arduino.h>

const int PWM_PIN = 5;
const int PWM_CH  = 0;
const int PWM_HZ  = 5000;
const int PWM_RES = 10;
const int PWM_MAX = (1 << PWM_RES) - 1;

void setup() {
  ledcSetup(PWM_CH, PWM_HZ, PWM_RES);
  ledcAttachPin(PWM_PIN, PWM_CH);
}

void loop() {
  for (int d = 0; d <= PWM_MAX; d += 8) {
    ledcWrite(PWM_CH, d);
    delay(5);
  }
  for (int d = PWM_MAX; d >= 0; d -= 8) {
    ledcWrite(PWM_CH, d);
    delay(5);
  }
}
