const int SAMPLE_PIN = A0;
const int N = 16;

int buf[N];
int idx = 0;
long sum = 0;

void setup() {
  Serial.begin(115200);
  for (int i = 0; i < N; i++) buf[i] = 0;
}

void loop() {
  int s = analogRead(SAMPLE_PIN);
  sum -= buf[idx];
  buf[idx] = s;
  sum += s;
  idx = (idx + 1) % N;
  Serial.println(sum / N);
  delay(100);
}
