#include <Arduino.h>
#include <ArduinoBLE.h>

BLEService svc("180A");
BLEUnsignedLongCharacteristic upMs("2AE2", BLERead | BLENotify);

void setup() {
  Serial.begin(115200);
  if (!BLE.begin()) {
    Serial.println("BLE init failed");
    while (true) { delay(1000); }
  }
  BLE.setLocalName("Sense");
  BLE.setAdvertisedService(svc);
  svc.addCharacteristic(upMs);
  BLE.addService(svc);
  upMs.writeValue((uint32_t)millis());
  BLE.advertise();
}

void loop() {
  BLE.poll();
  static unsigned long last = 0;
  if (millis() - last > 1000) {
    last = millis();
    upMs.writeValue((uint32_t)last);
  }
}
